class Solution:
    def countNumbers(self, l: str, r: str, b: int) -> int:
        MOD = 10**9 + 7
        def check(num):
            for i in range(len(num) - 1):
                if int(num[i], b) > int(num[i + 1], b):
                    return False
            return True

        def dfs(num, b, cur, res):
            if cur >= int(num, b):
                res[0] += 1
            if cur > int(num, b):
                return
            for i in range(b):
                dfs(num, b, cur * b + i, res)

        res = [0]
        dfs(r, b, 0, res)
        dfs(l, b, 0, res)
        return (res[0] - 1) % MOD
```

